TriggerOraclev10g.body:
DECLARE
    vro_parametro   tkr_parametros%ROWTYPE;
BEGIN
    IF :old.id_estado_pago = 1 AND :new.id_estado_pago = 2
    THEN
        IF pkgtkr_parametros_dao.f_existe (-44, vro_parametro) = TRUE
        THEN
            :new.no_envio_contable_fm := vro_parametro.valor_parametro;
        END IF;
    END IF;
END;
